import openai
import os
import re

# Load your OpenAI API key securely
openai.api_key = os.getenv("OPENAI_API_KEY")

def validate_input(user_input):
    # Basic validation to prevent prompt injection
    if not isinstance(user_input, str) or len(user_input) > 1000:
        raise ValueError("Invalid input")
    # Allow only alphanumeric and basic punctuation
    if not re.match(r'^[a-zA-Z0-9\s.,!?\'"-]+$', user_input):
        raise ValueError("Input contains invalid characters")
    return user_input

def get_chatbot_response(user_input):
    try:
        validated_input = validate_input(user_input)
        system_instructions = "You are a customer support assistant. Provide helpful and concise responses."
        prompt = f"{system_instructions}\nUser: {validated_input}\nAssistant:"
        
        response = openai.Completion.create(
            engine="text-davinci-003",
            prompt=prompt,
            max_tokens=150,
            temperature=0.5
        )
        
        return response.choices[0].text.strip()
    except Exception as e:
        return f"Error: {str(e)}"

# Example usage
